import{_ as a,o as s,c as t,ae as i}from"./chunks/framework.jfJLTIcL.js";const u=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"en/quick-start.md","filePath":"en/quick-start.md","lastUpdated":1775283834000}'),o={name:"en/quick-start.md"};function l(n,e,r,p,d,c){return s(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><h2 id="_1-install-dependencies" tabindex="-1">1. Install dependencies <a class="header-anchor" href="#_1-install-dependencies" aria-label="Permalink to &quot;1. Install dependencies&quot;">​</a></h2><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">npm install</span></span></code></pre></div><p>VILab now supports both Windows and Apple Silicon macOS desktop development from the same repository.</p><h2 id="_2-start-the-desktop-app" tabindex="-1">2. Start the desktop app <a class="header-anchor" href="#_2-start-the-desktop-app" aria-label="Permalink to &quot;2. Start the desktop app&quot;">​</a></h2><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">npm run dev</span></span></code></pre></div><p>On Apple Silicon macOS, you can also use the helper script:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/dev-mac.sh</span></span></code></pre></div><p>On Windows, the local Whisper runtime may require a 64-bit <code>libclang.dll</code> during Rust compilation. <code>npm run dev</code>, <code>npm run build</code>, and <code>npm run cargo:check</code> now try to auto-detect common install locations first. If <code>cargo</code> still fails inside <code>whisper-rs-sys</code>, set <code>LIBCLANG_PATH</code> to a directory that contains a compatible 64-bit <code>libclang.dll</code> and run the command again.</p><p>On Windows, the same startup path now also prepares ONNX Runtime automatically for built-in SenseVoice support. You normally do not need to install <code>onnxruntime.dll</code> by hand before running the desktop app.</p><p>On macOS, the first successful dictation workflow also requires you to grant:</p><ul><li>Microphone permission for audio capture</li><li>Accessibility permission for global shortcuts and paste-back into the focused app</li></ul><p>The current default macOS dictation shortcut is <code>Cmd+Shift+Option+D</code>.</p><p>This launches:</p><ul><li>The Vite renderer</li><li>The Tauri desktop shell</li><li>The embedded VILab HTTP service managed by the app</li></ul><h2 id="_3-confirm-the-service-url" tabindex="-1">3. Confirm the service URL <a class="header-anchor" href="#_3-confirm-the-service-url" aria-label="Permalink to &quot;3. Confirm the service URL&quot;">​</a></h2><p>In the desktop app, open <strong>Settings</strong> and check <strong>Server URL</strong>.</p><p>The current default is:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://127.0.0.1:8765</span></span></code></pre></div><h2 id="_4-check-health" tabindex="-1">4. Check health <a class="header-anchor" href="#_4-check-health" aria-label="Permalink to &quot;4. Check health&quot;">​</a></h2><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl http:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">127.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8765</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">health</span></span></code></pre></div><p>Expected response:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;serviceId&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;uuid&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;version&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0.1.6&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;publicModel&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;vilab-local-stt&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><code>publicModel</code> is the currently exposed STT model alias. It can represent either the active local model alias or the currently routed cloud STT alias.</p><h2 id="_5-choose-the-stt-mode" tabindex="-1">5. Choose the STT mode <a class="header-anchor" href="#_5-choose-the-stt-mode" aria-label="Permalink to &quot;5. Choose the STT mode&quot;">​</a></h2><p>Open <strong>Settings</strong> and configure <strong>Routing and models -&gt; STT mode</strong>:</p><ul><li><code>Local</code>: desktop dictation and <code>/v1/audio/transcriptions</code> use the active local speech runtime</li><li><code>Cloud</code>: desktop dictation and <code>/v1/audio/transcriptions</code> use the selected cloud provider and cloud STT model</li></ul><p>The Home page quick-start header now shows the current STT source and model name, for example:</p><ul><li><code>Local 路 Whisper Small</code></li><li><code>Local 路 SenseVoice</code></li><li><code>Cloud 路 whisper-large-v3-turbo</code></li></ul><p>Settings now save automatically after each change. You do not need to click a separate save button after switching STT mode, dictation priority, providers, or local models.</p><h2 id="_6-if-using-local-stt-install-and-activate-a-local-speech-model" tabindex="-1">6. If using local STT, install and activate a local speech model <a class="header-anchor" href="#_6-if-using-local-stt-install-and-activate-a-local-speech-model" aria-label="Permalink to &quot;6. If using local STT, install and activate a local speech model&quot;">​</a></h2><p>Before desktop dictation or LAN clients can call <code>/v1/audio/transcriptions</code>, open <strong>Settings</strong> and configure <strong>Local speech models</strong>:</p><ul><li>Download a built-in model such as <code>Whisper Base</code>, <code>Whisper Small</code>, or <code>SenseVoice</code>, or</li><li>Place a compatible Whisper.cpp <code>.bin</code> model file in the models directory and refresh</li><li>Activate the model you want the host to use</li></ul><p>The desktop app and the embedded HTTP service now share the same local speech runtime.</p><p>Built-in SenseVoice is installed as a managed directory model. Manual custom local models are still limited to Whisper.cpp <code>.bin</code> files in this phase.</p><p>Built-in SenseVoice is supported on both Windows and Apple Silicon macOS in this release.</p><p>If you select <code>Cloud</code> STT mode instead, configure the cloud provider and cloud STT model in the same routing section.</p><h2 id="_7-choose-the-transcript-output-mode" tabindex="-1">7. Choose the transcript output mode <a class="header-anchor" href="#_7-choose-the-transcript-output-mode" aria-label="Permalink to &quot;7. Choose the transcript output mode&quot;">​</a></h2><p>Open <strong>Settings</strong> and configure <strong>Transcript mode</strong> and <strong>Scene mode</strong> for desktop dictation:</p><ul><li><code>Verbatim</code> keeps the output closest to the raw transcript</li><li><code>Smart Clean</code> removes low-risk fillers, repetitions, and obvious self-repairs using only local cleanup rules</li><li><code>Polished</code> runs the cloud transform provider after smart-clean and can shape the result for <code>chat</code>, <code>email</code>, or <code>notes</code></li></ul><p>History now keeps multiple output variants per session so you can switch between raw, smart-clean, and polished results without losing the original transcript.</p><h2 id="_8-configure-text-transform-providers" tabindex="-1">8. Configure text transform providers <a class="header-anchor" href="#_8-configure-text-transform-providers" aria-label="Permalink to &quot;8. Configure text transform providers&quot;">​</a></h2><p>Cloud providers are now used for polished dictation, cleanup, rewrite, and other text transforms.</p><p>In <strong>Settings</strong>, configure:</p><ul><li>Transform provider</li><li>API key</li><li>API base URL</li><li>Rewrite model</li></ul><h2 id="_9-open-prompt-lab" tabindex="-1">9. Open Prompt Lab <a class="header-anchor" href="#_9-open-prompt-lab" aria-label="Permalink to &quot;9. Open Prompt Lab&quot;">​</a></h2><p>In the sidebar footer, use <strong>Test platform</strong> under <strong>Open Docs</strong> to launch Prompt Lab in your browser.</p><p>Prompt Lab is intended for internal prompt and model evaluation:</p><ul><li><code>Smart Clean</code> runs local rules only and should finish almost instantly</li><li><code>Polished</code> uses the selected provider, model, preset, and optional prompt override</li><li>Runs do not write to the normal session history</li></ul><h2 id="_10-create-an-external-api-key" tabindex="-1">10. Create an external API key <a class="header-anchor" href="#_10-create-an-external-api-key" aria-label="Permalink to &quot;10. Create an external API key&quot;">​</a></h2><p>In <strong>Settings -&gt; External API keys</strong>:</p><ul><li>Create one key per project, script, device, or integration</li><li>Do not distribute the <code>adminKey</code> to normal callers</li><li>Copy the new key immediately; the full value is only shown once</li></ul><h2 id="_11-build-a-packaged-macos-app" tabindex="-1">11. Build a packaged macOS app <a class="header-anchor" href="#_11-build-a-packaged-macos-app" aria-label="Permalink to &quot;11. Build a packaged macOS app&quot;">​</a></h2><p>On Apple Silicon macOS:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build:mac</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/run-mac-app.sh</span></span></code></pre></div><p><code>npm run build:mac</code> produces the packaged <code>.app</code> and <code>.dmg</code>, while <code>run-mac-app.sh</code> opens the newest built app bundle for a local smoke test.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="/docs/en/lan-deployment">LAN Deployment</a></li><li><a href="/docs/en/api-keys">API Keys</a></li><li><a href="/docs/en/integrations">Integrations</a></li></ul>`,58)])])}const k=a(o,[["render",l]]);export{u as __pageData,k as default};
